var b="url",c="采购订单创建（新增）.html",d="generationDate",e=new Date(1781588953734.96),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="page",s="packageId",t="ca9becaa1b2e475a95b36a579d460a75",u="type",v="Axure:Page",w="采购订单创建（新增）",x="notes",y="annotations",z="fn",A="1",B="ownerId",C="16f8e9a2c9c04a22adb9bfd3c9eb7f8a",D="label",E="* 采购类型：",F="说明",G="<p><span>1.默认[采购类型]中第一个“开启”的采购类型</span></p><p><span>2.数据源：[采购类型]中“开启”的采购类型</span></p><p><span>3.右侧无“×”，无法清除</span></p>",H="2",I="5948fc48d100402d9e6a28e81991feab",J="采购日期：",K="<p><span>1.默认值：当前日期</span></p><p><span>2.格式：年/月/日</span></p>",L="3",M="eedba69f1cd44aed82821a48593c09ca",N="* 属主：",O="<p><span>1.数据源：[ 属主 ]</span></p><p><span>2.默认值：根据数据源数量赋值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a. [ 属主 ] 数据 = 1 ：默认对应的唯一属主</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b. [ 属主 ] 数据 ≥ 2 ：默认为空</span></p>",P="4",Q="2eda750bd6654903a105603f11f515e5",R="* 入库仓库：",S="<p><span>数据源：仓库属性为“余料/物料/面料/辅料”的仓库</span></p>",T="5",U="e00006adf03f41618b0d70e60c679450",V="含税总额：",W="<p><span>清单中的Σ“含税总额”</span></p>",X="6",Y="8f1966d49e3a4d81b13e540826673387",Z="* 要求交货日期：",ba="7",bb="6397b39ef1ce4eb4abdbd49138cf8e90",bc="操作",bd="<p><span>【新增】</span></p><p><span>1.若当前采购订单只关联了一个订单/款，新增SKU行时也同步唯一的订单号或款号</span></p><p><span>2.若当前采购订单只关联了多个订单/款，新增SKU行为空，不关联任何订单号或款号</span></p>",be="8",bf="54391662dd3243a7a90e81f0219ca9e8",bg=" 物料SKU编码",bh="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">物料SKU编码</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1. 数据源：采购订单内选择供应商对应的物料的sku。默认展示10条。向下滚动可加载新的数据。</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2. SKU支持模糊搜索（物料名称、物料SKU）</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">3. 点击物料SKU，以字节阵形式展示 物料SKU编码 物料名称 规格 克重&nbsp; 颜色</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">4. 选中物料编码SKU，相应的物料名称、规格、克重、颜色、价格、税率自动带出</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">5.变更顶部供应商后，已生成的物料清单无须变更</span></p>",bi="9",bj="f06f7b5197a444c68c18b4141144c1cd",bk=" 物料编码",bl="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">物料编码</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1. 数据源：下拉选项较之前不做改变，仅展示顶部选中供应商下的物料</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2. 选中物料后，</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">自动带出该物料的第一个供应商为对应选择的SKU信息</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">，含SKU编码 规格 克重&nbsp; 颜色 、价格、税率</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">3. 变更顶部供应商后，已生成的物料清单无须变更</span></p>",bm="10",bn="68575931d5044d4a9252753e06ddd0bd",bo="物料名称",bp="<p><span>跟随选中的“物料编码”对应的[物料名称]</span></p>",bq="11",br="e3c18a27e8624216b84ca20efbcf3452",bs="规格/门幅",bt="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1. 数据源：数据源：物料明细中该物料已创建的规格。</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2. 展示样式：“规格”(“克重”)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">3. 变更规格后：无须变更“颜色”，但“物料SKU编码”需按当前“物料-规格-克重-颜色”查找一下是否存在对应SKU：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; 3.1&nbsp; 若存在，将对应SKU调过去</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 3.1.1&nbsp; 若该sku存在供应商为当前供应商，价格、税率同步过来</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 3.1.2&nbsp; 若该sku不存在供应商为当前供应商，不用处理价格、税率</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; 3.2&nbsp; 若不存在，SKU字段展示为空，供应商、价格、税率不进行变更</span></p>",bu="12",bv="5e8e4b9610174595b354b917e84d9d1b",bw="克重",bx="<p><span>跟随物料的“规格/门幅”</span></p>",by="13",bz="b49ba038147f4bac9f7cb42e218d7abc",bA="颜色",bB="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#333333;\">颜色</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1. 数据源：系统中所有颜色，可进行模糊搜索颜色和色号</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2. “颜色”字体颜色区分标识： 若在物料明细中：蓝色 ； 颜色库中但非物料明细中：黑色</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">3. 变更颜色后：“物料SKU编码”需要按照当前“物料-规格-克重-颜色”查找一下是否存在对应SKU：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; 3.1&nbsp; 若存在，将对应SKU调过去</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 3.1.1&nbsp; 若该sku存在供应商为当前供应商，价格、税率同步过来</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; 3.1.2&nbsp; 若该sku不存在供应商为当前供应商，不用处理价格、税率</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; 3.2&nbsp; 若不存在，SKU字段展示为空，供应商、价格、税率不进行变更</span></p>",bC="14",bD="96d3b8ed20cc4ce8826309d6983b1d71",bE="单位",bF="<p><span>跟随选中的“物料编码”对应的[物料单位]</span></p>",bG="15",bH="fb2d93e3bb0a41678119e515fbea632d",bI="换算单位",bJ="<p><span>1.该字段表头绿色</span></p><p><span>2.该列为文本展示</span></p><p><span>3.跟随选中的“物料编码”对应的启用的[第二单位]</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.若未启用第二单位，直接展示为空</span></p><p><span><br></span></p><p><span>附：若后期可对同一物料设置多单位后再处理为下拉框</span></p>",bK="16",bL="8f1bbfef42154f00adfa5782ca5b63ed",bM="换算比例",bN="<p><span>1.该字段表头绿色</span></p><p><span>2.默认值跟随每次SKU的变更（每切换SKU编码、规格/门幅、颜色使SKU编码变更时，可重新赋默认值）</span></p><p><span>3.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0484EA;\">仅查到的物料开启了第二单位，且SKU已存在，且SKU对应的“第二单位比例”不为0时才重新赋值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.若对应物料未开启第二单位，无须重新赋默认值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.若对应物料开启了第二单位，但未生成对应SKU，无须重新赋默认值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.若对应物料开启了第二单位，存在对应SKU，但SKU设置的“第二单位比例”为0，无须重新赋默认值</span></p><p><span>4.保留三位小数</span></p>",bO="17",bP="5a56236e60cc453b94a525c92ae1788a",bQ="换算用量",bR="<p><span>1.该字段表头绿色</span></p><p><span>2.保留两位小数</span></p><p><span>3.若“换算用量”产生变更，将重新计算“采购数量”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a.若“换算比例”为0.00，不作计算；</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b.若“换算比例”不为0.00，重新计算“采购数量”(采购数量=换算比例*换算用量)；</span></p><p><span>4.Tooltips：将根据“换算用量”重新计算“采购数量”；采购数量=换算比例*换算用量</span></p>",bS="18",bT="8d72237e7e12460ebab2f884ff60b600",bU="计划件数",bV="<p><span>1.格式：整数</span></p><p><span>2.编辑域的值将影响“计划用量”的计算</span></p>",bW="19",bX="74acab845ff04cfbb52eb28ed40ae9a8",bY="计划用量",bZ="<p><span>1.默认值：跟随上游</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.采购任务整理：同名&quot;计划用量&quot;字段值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.生产采购需求：取&quot;理论采购&quot;字段值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; c.样衣采购需求：取&quot;理论采购&quot;字段值</span></p><p><span>2.每当前行的“单耗”或“计划件数”的变更，将重新计算“计划用量”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.计划用量=单耗*计划件数</span></p><p><span>3.Tooltips：计划用量=单耗*计划件数</span></p>",ca="20",cb="a5992a32c64340c8b9d0efa35b4ab94a",cc="建议采购量",cd="<p><span>1.根据 计划用量、广义需求数量、广义库存数量 进行计算</span></p><p><span>2.Tooltips：建议采购数量=计划用量+广义需求数量-广义库存数量</span></p>",ce="21",cf="07af4f5a9034445ea6a1ae9cda42ac90",cg="采购数量",ch="<p><span>1.保留两位小数</span></p><p><span>2.Tooltips：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">跟随“换算比例”、“换算用量”自动计算。采购数量=换算比例*换算用量</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\"><br></span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">其它相关逻辑</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">在</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">[采购订单创建]</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">的详情页变更“采购数量”时，保存后覆盖'计划采购数量'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">在</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">[采购订单操作]</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">的详情页变更“采购数量”时，不变更'计划采购数量'</span></p>",ci="22",cj="6da2cdc5dc2c4f4793d68afe160f3a65",ck="广义需求数量",cl="<p><span>广义需求量指已经到采购订单的工单未领料的数量；</span></p>",cm="23",cn="b11bd0e0181e4d43bb0e763aec4823ae",co="在途数量",cp="<p><span>已经【生成待入库任务】的订单的对应数量-当前入库数量</span></p>",cq="24",cr="812517785cd042adbb8e28f7d75304de",cs="未税单价",ct="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">该列展示/隐藏</span><span>：跟随数据字典[system_config_COMPANY_TYPE]判断</span></p><p><span>1.[system_config_COMPANY_TYPE == 23 (佳美) ]：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">隐藏</span></p><p><span>2.[system_config_COMPANY_TYPE ! = 23 ]：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">展示</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">字段描述</span></p><p><span>1.格式：保留</span><span style=\"color:#D9001B;\">4位</span><span>小数</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.手动输入：无法输入第5位</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.计算结果：四舍五入后保留4位小数</span></p><p><span>2.恒定计算公式：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">含税单价=</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">未税单价</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">(1+税率/100)</span></p><p><span>3.自动计算方式</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.每变更“未税单价”时，根据&quot;税率&quot;重新计算“含税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.每变更“税率”时，根据&quot;含税单价&quot;重新计算“未税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.每变更“含税单价”时，根据&quot;税率&quot;重新计算“未税单价”</span></p>",cu="25",cv="ca66caa69e5e46c680d5af6229b620cb",cw="税率(%)",cx="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">该列展示/隐藏</span><span>：跟随数据字典[system_config_COMPANY_TYPE]判断</span></p><p><span>1.[system_config_COMPANY_TYPE == 23 (佳美) ]：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">隐藏</span></p><p><span>2.[system_config_COMPANY_TYPE ! = 23 ]：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">展示</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">字段描述</span></p><p><span>1.格式：整数</span></p><p><span>2.恒定计算公式：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">含税单价=未税单价(1+</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">税率</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">/100)</span></p><p><span>3.自动计算方式</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.每变更“未税单价”时，根据&quot;税率&quot;重新计算“含税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.每变更“税率”时，根据&quot;含税单价&quot;重新计算“未税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.每变更“含税单价”时，根据&quot;税率&quot;重新计算“未税单价”</span></p>",cy="26",cz="6da5d80bbf1347a8a0813a89dd90c78b",cA="含税单价",cB="<p><span>1.格式：保留</span><span style=\"color:#D9001B;\">3位</span><span>小数</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.手动输入：无法输入第4位</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.计算结果：四舍五入后保留3位小数</span></p><p><span>2.恒定计算公式：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">含税单价</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">=未税单价(1+税率/100)</span></p><p><span>3.自动计算方式</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.每变更“未税单价”时，根据&quot;税率&quot;重新</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">计算当前</span><span>“含税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.每变更“税率”时，根据&quot;含税单价&quot;重新计算“未税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.每</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">变更当前</span><span>“含税单价”时，根据&quot;税率&quot;重新计算“未税单价”</span></p><p><span><br></span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\"><br></span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">其它相关逻辑</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">在</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">[采购订单创建]</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">的详情页变更“含税单价”时，保存后覆盖'计划采购单价'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">在</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">[采购订单操作]</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">的详情页变更“含税单价”时，不变更'计划采购单价'</span></p>",cC="27",cD="b3e84c28c2504fdbaf5418abcb3f5d06",cE="物料合计(含)",cF="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.计算方式：</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#0000FF;\">物料合计(含)</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#555555;\">=</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">采购数量*含税单价</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; a.计算结果保留4位小数</span></p>",cG="28",cH="fa6cf5f989334afc97b183f3a7243208",cI="附加费用(含)",cJ="<p><span>保留4位小数</span></p>",cK="29",cL="b24506915f7e43a4b270cba5e6e5ded9",cM="是否检验",cN="<p><span>默认值跟随配置项system_config_purchase_isCheck（0-否 1-是）</span></p>",cO="30",cP="838dfb83f51e4035b5f598dcc1795e0a",cQ="二次加工",cR="<p><span>默认值跟随配置项system_config_purchase_isProcessing（0-否 1-是）</span></p>",cS="31",cT="d83b411dc9c444d1b5913e080557cc03",cU="PO",cV="<p><span>跟随“订单号”</span></p>",cW="32",cX="ceb5a9270e5648438553112e43367b65",cY="包装数",cZ="<p><span>1.默认为空</span></p><p><span>2.格式：仅自然数</span></p>",da="33",db="f9c79b30fc084189bfc912e561d855b0",dc="含税总额",dd="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.计算方式：</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#0000FF;\">含税总额</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#555555;\">=</span><span>物料合计(含)+附加费用(含)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; a.计算结果保留4位小数</span></p>",de="34",df="bb99b56c466141adbbb37cd06a8042ce",dg="<p><span>不用全展示，只展示有数量的颜色/尺码</span></p>",dh="35",di="56d5157c31c440c9984764d4add0fef1",dj="36",dk="5d3ac1f6d87147658f2bdc62d535249a",dl="保存",dm="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#066E00;\">直接创建</span></p><p><span>1.判断是否清单内“规格”和“颜色”必填，否则提示：物料规格、颜色不能为空</span></p><p><span>2.校验“采购数量”是否存在有值为0：</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.不存在值为0，不作处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.存在值为0，跟随配置项[system_config_wms_purchase_quantity_can_be_zero]校验</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.配置项=0；提示：采购数量不能为0</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b2.配置项=1；弹窗</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">二次确认</span><span>“当前存在采购数量为0，确认保存”</span></p><p><span>3.判断是否有SKU列为空的数据，若存在为空的，弹窗提示</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#F96868;\">未生成SKU编码</span><span>，二次确认后制动生成SKU编码</span></p><p><span>4.保存后返回列表页</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">附其它逻辑</span></p><p><span>1.将“采购数量”赋值给“计划采购数量”</span></p>",dn="style",dp="baseStyle",dq="627587b6038d43cca051c114ac41ad32",dr="pageAlignment",ds="center",d